import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"22. Fixed Term Employment","description":"","frontmatter":{"title":"22. Fixed Term Employment","eba":"Biomedical Engineers 2025-2028","topics":["employment"]},"headers":[],"relativePath":"ebas/biomedical-engineers/employment/22-fixed-term-employment.md","filePath":"ebas/biomedical-engineers/employment/22-fixed-term-employment.md"}'),a={name:"ebas/biomedical-engineers/employment/22-fixed-term-employment.md"};function i(s,e,p,l,c,m){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_22-fixed-term-employment" tabindex="-1">22. Fixed Term Employment <a class="header-anchor" href="#_22-fixed-term-employment" aria-label="Permalink to &quot;22. Fixed Term Employment&quot;">​</a></h1><p>Fixed term contracts entered into after 6 December 2023 are subject to this clause and the Act, the terms of the Act will prevail.</p><p><strong>22.1</strong> General</p><p><strong>(a)</strong> A fixed term Employee is an Employee who is employed for a specified period of time, which period is known at the commencement of the contract, or for a specified task such as a project or replacement of an absent employee.</p><p><strong>(b)</strong> Subject to this clause 22, fixed term employment will not be used to fill an ongoing position, or offered through consecutive fixed term employment contracts for work that is otherwise ongoing.</p><p><strong>(c)</strong> If the Employer enters into a fixed term contract with an Employee in contravention of subclauses 22.3(a), 22.4 and/or 22.5 below:</p><p><strong>(i)</strong> the term of the contract that provides that the contract will terminate at the end of the specified period is taken to have no effect; and</p><p><strong>(ii)</strong> the contravention is taken not to affect the validity of any other term of the contract.</p><p><strong>22.2</strong> Exceptions Subclauses 22.3(a), 22.4 and 22.5 below do not apply to a fixed term contract if:</p><p><strong>(a)</strong> the Employee is engaged:</p><p><strong>(i)</strong> to perform only a distinct and identifiable task involving specialised skills; or</p><p><strong>(ii)</strong> in relation to a training arrangement; or</p><p><strong>(iii)</strong> to undertake essential work during a peak demand period; or</p><p><strong>(iv)</strong> to undertake work during emergency circumstances; or</p><p><strong>(v)</strong> during a temporary absence of another employee (e.g. Parental/Long Service Leave/Work Cover backfill); or</p><p><strong>(b)</strong> in the year it’s entered into, the amount of the Employee&#39;s earnings is above the high income threshold for that year; or</p><p><strong>(c)</strong> it relates to a position for the performance of work that:</p><p><strong>(i)</strong> is funded in whole or in part by government funding or funding of a kind prescribed by the Regulations for the purposes of this subclause; and</p><p><strong>(ii)</strong> the funding is payable for a period of more than 2 years; and</p><p><strong>(iii)</strong> there are no reasonable prospects that the funding will be renewed after the end of that period.</p><p><strong>22.3</strong> Time Limitations</p><p><strong>(a)</strong> A fixed term contract will be for a maximum of 2 years duration. This time limitation includes any extensions or renewals.</p><p><strong>(b)</strong> Where one of the exceptions outlined at subclause 22.2(a) or 22.2(c) applies, fixed term appointments to a specific position or consecutive fixed term appointments involving the same or substantially similar work, will be for a maximum of 3 years duration except in relation to:</p><p><strong>(i)</strong> a training arrangement of longer than 3 years duration; or</p><p><strong>(ii)</strong> special projects, or</p><p><strong>(iii)</strong> research projects, or</p><p><strong>(iv)</strong> a parental leave back-fill role, or</p><p><strong>(v)</strong> back-fill of an Employee who is posted overseas.</p><p><strong>(c)</strong> Where subclause 22.3(b) applies and the Employer wants to continue the role for a duration beyond 3 years, the Employer must follow the process for conversion to ongoing employment as outlined at <a href="/eba/ebas/allied-health/appendices/3-allowances-and-top-of-band-payments.html">Appendix 3</a>.</p><p><strong>22.4</strong> Renewal Limitations A fixed term contract cannot:</p><p><strong>(a)</strong> include an option to extend or renew the contract more than once, or</p><p><strong>(b)</strong> extend or renew the contract so that the period of employment is longer than 2 years.</p><p><strong>22.5</strong> Consecutive Contract Limitations An Employee cannot be offered a new fixed term contract if:</p><p><strong>(a)</strong> their previous contract was also for a fixed term, and</p><p><strong>(b)</strong> their previous contract and the new contract are for the same, or substantially similar, work, and</p><p><strong>(c)</strong> there is substantial continuity in the employment relationship between the previous and new contracts, and</p><p><strong>(d)</strong> any of the following apply:</p><p><strong>(i)</strong> the previous contract contained an option to extend that was used,</p><p><strong>(ii)</strong> the total period of employment for both the previous and new fixed term contract is more than 2 years,</p><p><strong>(iii)</strong> the new fixed term contract contains an option to renew or extend, or</p><p><strong>(iv)</strong> there was an initial contract in place (before the previous contract): <strong>(A)</strong> that was for a fixed term <strong>(B)</strong> that was for the same or substantially similar work, and <strong>(C)</strong> where there was substantial continuity in the employment relationship.</p><p><strong>22.6</strong> Disputes In the event of a dispute arising over the provisions of this clause 22, the dispute resolution procedure at <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> of this Agreement applies.</p>',42)])])}const h=t(a,[["render",i]]);export{g as __pageData,h as default};
